declare @form nvarchar(4000), @name nvarchar(4000), @defaultForm varchar(33), @reportType char(1)
select @form = '', @name = ''
select @reportType = rtrim(val) from options where name = 'm_kieu_bc'
select top 1 @defaultForm = rtrim(upper(form)) from v20dmmaubc where ma_maubc = '&defaultForm;' and (kieu_bc = 0 or kieu_bc = @reportType) and nd_yn = 1
if @defaultForm is null select top 1 @defaultForm = rtrim(upper(form)) from v20dmmaubc where ma_maubc = '&defaultForm;' and (kieu_bc = 0 or kieu_bc = @reportType)

select @form = @form + rtrim(upper(form)) + char(255), @name = @name + case when lower(@@language) = 'v' then rtrim(ten_maubc) else rtrim(ten_maubc2) end + char(255) from v20dmmaubc where ma_maubc = '&defaultForm;' and (kieu_bc = 0 or kieu_bc = @reportType)
select @form = left(@form, len(@form) - 1), @name = left(@name, len(@name) - 1)
select 'this._itemValue=''' + rtrim(@form) + ''';this._itemText=''' + dbo.FastBusiness$Function$EncodeScript(@name) + '''; this._defaultForm = ''' + @defaultForm + ''';initForm(this);' as message
return




    &XMLWhenFilterLoading;
    &XMLWhenFilterClosing;



select @ngay_bd as ngay_bd, case
  when @@language = 'V' then case
    when @kieu_bc = '1' then N'ngày'
    when @kieu_bc = '2' then N'tuần'
    when @kieu_bc = '3' then N'tháng'
    when @kieu_bc = '4' then N'quý'
    when @kieu_bc = '5' then N'nửa năm'
    when @kieu_bc = '6' then 'năm'
  end else case
    when @kieu_bc = '1' then N'Day'
    when @kieu_bc = '2' then N'Week'
    when @kieu_bc = '3' then N'Month'
    when @kieu_bc = '4' then N'Quater'
    when @kieu_bc = '5' then N'Half a Year'
    when @kieu_bc = '6' then 'Year'
  end
end as bc_theo, cast(@ky_bc as varchar(10)) as ky_bc
exec rs_rptIncomeStatementMultiPeriod @kieu_bc, @ky_bc, @ngay_bd, @ma_dvcs, @form, @mau_bc, @@language, @@userID, @@admin







      &OutlineEntry;
      /* <flatten type="Javascript"> */
function active$VoucherFilter$(f) {
  f.add_onResponseComplete(on$Filter$ResponseComplete);
  changeLookupReadonly(f, 'ma_dvcs');
}
function close$VoucherFilter$(f) {try {f.remove_onResponseComplete(on$Filter$ResponseComplete);} catch (ex) {}}
function on$Filter$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result, g = f.grid;
  switch (context) {
    case 'Checking':
      var dTo = f.getItem('ngay_bd').value, x = f.getItem('form').selectedIndex, y = f.getItem('form').options;
      var formName = y[x].text;
      var y = f.getItemValue('kieu_bc'), z = f.getItemValue('ky_bc'), v = g._language == 'v';
      var t;
      switch (y) {
        case '1':
          t = (v ? 'Báo cáo theo: ngày' : 'Report by: Day');
          break;
        case '2':
          t = (v ? 'Báo cáo theo: tuần' : 'Report by: Week');
          break;
        case '3':
          t = (v ? 'Báo cáo theo: tháng' : 'Report by: Month');
          break;
        case '4':
          t = (v ? 'Báo cáo theo: quý' : 'Report by: Quarter');
          break;
        case '5':
          t = (v ? 'Báo cáo theo: nửa năm' : 'Report by: Half a Year');
          break;
        case '6':
          t = (v ? 'Báo cáo theo: năm' : 'Report by: Year');
          break;
        default:
          break;
      }
      g._alterTitle = [null, [['%t', t, true], ['%p', z, true], ['%d', dTo, true]]];

      var c = f.getItemValue('mau_bc') + String.fromCharCode(255) + z;
      if (!g._v) g._v = c;
      if (g._v != c) {
        remove$GridReport$Filter(g);
        g._v = c;
      }
      break;
    default:
      break;
  }
}
function initForm(f) {
  var o = f.getItem('form'), value = f._itemValue.split(String.fromCharCode(255)), text = f._itemText.split(String.fromCharCode(255)), index;
  for (var i = 0; i < value.length; i++) {
    o.options[i] = new Option(text[i], value[i]);
    if (!index && f._defaultForm == value[i]) index = i;
  }
  if (!index) index = 0;
  o.options[index].selected = true;
}

function remove$GridReport$Filter(g) {
  var r = name, field;
  for (var j = g._filter.length - 1; j >= 0; j--) {
    var x = g._filter[j].match(/^([\w\$]+):/)[1];
    name = $func.trim(x);
    field = $func.findField(name, g._fields);
    if (x.indexOf('tien') != -1) {
      if (field) field.FilterPanelValue = '';
      Array.removeAt(g._filter, j);
    }
  }
}/* </flatten> */



